import * as React from 'react';

const Counter:React.FC = () => {

 const [count, setCount] = React.useState&lt;number>(0);

 return (
  &lt;>
   &lt;p>Count: {count}&lt;/p>
   &lt;button onClick={() => setCount(count + 1)}>Increment&lt;/button>
  &lt;/>
 ) 
}

export default Counter

import * as React from 'react';

const User:React.FC = () => {
 const [user] = React.useState&lt;{name:string, id:string}|null>({
  id: '4789rzr230894n',
  name: 'Monika Musterfrau'
 });

 return (
  &lt;>
   &lt;h2>User&lt;/h2>
   &lt;p>{user?.name}&lt;/p>
   &lt;p>({user?.id})&lt;/p>
  &lt;/>
 )
}

export default User

import * as React from 'react';

type User = {
 id: string;
 name: string;
};

const Liste: React.FC = () => {
 const [users] = React.useState&lt;User[]>([
  {
   id: '43709n430n',
   name: 'Max Mustermann',
  }, {
   id: '783043tß0v29',
   name: 'Erika Exempel',
  },
 ]);

 return (
  &lt;>
   &lt;h2>Liste&lt;/h2>
    {users.map((user) => (
     &lt;div key={user.id}>
      &lt;p>{user.name}&lt;/p>
     &lt;/div>
    ))}
  &lt;/>
 );
};

export default Liste;
